head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;
scwin.userNm = scwin.memJson.userNm;
scwin.gv_loabranCd = scwin.memJson.loUpperLobranCd


scwin.onpageload = function () {};

// UDC에 값 세팅 방법
// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function () {
    console.log("----------- onUdcCompleted");
    $c.gus.cfDisableObjects([btn_Save]);
    lc_reqDeptCd.setValue(scwin.gv_loabranCd)
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    // ds_condition.UseChangeInfo = false;
    // tr_search.post();
    $c.sbm.execute(sbm_search);
}

//-------------------------------------------------------------------------
// 저장시 호출 되는 함수
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    // 필수입력사항 확인
    if (!$c.gus.cfValidate([gr_vehclInsuranceChangeMgnt])) {
        return;
    }

    // 변경된 사항이 있는지 확인.
    if (!ds_vehclInsuranceChangeMgnt.getModifiedIndex().length) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    let rowCnt = ds_vehclInsuranceChangeMgnt.getTotalRow()

    for (var i = 0; i < rowCnt; i++) {

        let rowData = ds_vehclInsuranceChangeMgnt.getRowJSON(i);

        let chkCarInsuranceYearStdDt = rowData["carInsuranceYearStdDt"];
        let chkCarInsuranceYearEndDt = rowData["carInsuranceYearEndDt"];
        let chkLuggageInsuranceYearStdDt = rowData["luggageInsuranceYearStdDt"];
        let chkLuggageInsuranceYearEndDt = rowData["luggageInsuranceYearEndDt"];
        let chkSelfVehclYn = rowData["selfVehclYn"];
        let chkSfdmgVehclYn = rowData["sfdmgVehclYn"];
        let chkGlassYn = rowData["glassYn"];
        let chkFrizYn = rowData["frizYn"];

        //시작일자가 종료일자 이전인지 check
        if (!$c.gus.cfIsAfterDate(chkCarInsuranceYearStdDt, chkCarInsuranceYearEndDt)) {
            await $c.win.alert(i + "번째 행 자동차보험 정보 기간(1년)의 시작일자가 종료일자 전 이어야 합니다");
            return;
        }

        //시작일자가 종료일자 이전인지 check
        if (!$c.gus.cfIsAfterDate(chkLuggageInsuranceYearStdDt, chkLuggageInsuranceYearEndDt)) {
            await $c.win.alert(i + "번째 행 적재물보험 정보 기간(1년)의 시작일자가 종료일자 전 이어야 합니다");
            return;
        }

        //chkSfdmgVehclYn chkGlassYn chkFrizYn chkUmbrellaPolicyYn

        if (chkSelfVehclYn == 1) {		// 자차여부
            var chkSelfVehclStdDt = rowData["selfVehclStdDt"];
            var chkSelfVehclEndDt = rowData["selfVehclEndDt"];

            if (chkSelfVehclStdDt == '' || chkSelfVehclEndDt == '') {
                await $c.win.alert(i + "번째 행 자차여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkSelfVehclStdDt, chkSelfVehclEndDt)) {
                await $c.win.alert(i + "번째 행 자차여부 선택시 자차기간 시작일자가 종료일자 전 이어야 합니다");
                return;
            }
        }

        if (chkSelfVehclYn == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(i, "selfVehclStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(i, "selfVehclEndDt", '');
        }

        if (chkSfdmgVehclYn == 1) {		// 자손여부
            var chkSfdmgVehclStdDt = rowData["sfdmgVehclStdDt"];
            var chkSfdmgVehclEndDt = rowData["sfdmgVehclEndDt"];

            if (chkSfdmgVehclStdDt == '' || chkSfdmgVehclEndDt == '') {
                await $c.win.alert(i + "번째 행 자손여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkSfdmgVehclStdDt, chkSfdmgVehclEndDt)) {
                await $c.win.alert(i + "번째 행 자손여부 선택시 자손여부 시작일자가 종료일자 전 이어야 합니다");
                return;
            }
        }

        if (chkSfdmgVehclYn == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(i, "sfdmgVehclStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(i, "sfdmgVehclEndDt", '');
        }

        if (chkGlassYn == 1) {			// 유리여부
            var chkGlassStdDt = rowData["glassStdDt"];
            var chkGlassEndDt = rowData["glassEndDt"];

            if (chkGlassStdDt == '' || chkGlassEndDt == '') {
                await $c.win.alert(i + "번째 행 유리여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkGlassStdDt, chkGlassEndDt)) {
                await $c.win.alert(i + "번째 행 유리여부 선택시 유리여부 시작일자가 종료일자 전 이어야 합니다");
                return;
            }
        }

        if (chkGlassYn == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(i, "glassStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(i, "glassEndDt", '');
        }

        if (chkFrizYn == 1) {				// 냉동여부
            var chkFrizStdDt = rowData["frizStdDt"];
            var chkFrizEndDt = rowData["frizEndDt"];

            if (chkFrizStdDt == '' || chkFrizEndDt == '') {
                await $c.win.alert(i + "번째 행 냉동여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkFrizStdDt, chkFrizEndDt)) {
                await $c.win.alert(i + "번째 행 냉동여부 선택시 냉동여부 시작일자가 종료일자 전 이어야 합니다");
                return;
            }
        }

        if (chkFrizYn == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(i, "frizStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(i, "frizEndDt", '');
        }
    }

    let messageStr = MSG_CM_CRM_001;
    let ret = await $c.win.confirm(messageStr);

    if (ret) {
        await $c.sbm.execute(sbm_save);
    }
}



//-------------------------------------------------------------------------
// 조회조건 초기화
//-------------------------------------------------------------------------
scwin.f_InitObjects = function () {
    $c.gus.cfInitObjects(table1, null);
}


//-------------------------------------------------------------------------
// 엑셀저장
//-------------------------------------------------------------------------
scwin.f_GridToExcel = function (gr_groupCode, gridName) {

    let rowCnt = ds_vehclInsuranceChangeMgnt.getTotalRow()
    if (rowCnt <= 0) {
        $c.win.alert("차량보험일괄갱신 내역이 존재하지않습니다.");
        return false
    }
    // cfGridToExcel(gr_groupCode, gridName, "C:\\" + gridName + ".xls", 4 + 8 + 16);

    const grdObj = gr_vehclInsuranceChangeMgnt;
    const infoArr = [];
    const options = {
        fileName: "차량보험일괄갱신내역" + ".xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "차량보험일괄갱신내역"
    };
    $c.data.downloadGridViewExcel(grdObj, options, infoArr);
}

// <!-- 엑셀업로드 Tr -->
scwin.sbm_save_submitdone = function (e) {
    $c.win.alert(MSG_CM_INF_001);
    $c.gus.cfDisableObjects([btn_Save]);
    scwin.f_Retrieve();
};


scwin.sbm_search_submit = function (e) {
    ds_condition.set("reqDeptCd", lc_reqDeptCd.getValue());
    ds_condition.set("reqCarInsuranceEndDt", ed_reqCarInsuranceEndDt.getValue());
    ds_condition.set("reqVehclNo", txt_reqVehclNo.getValue())
    ds_condition.set("reqDrcrNo", txt_reqDrcrNo.getValue())
    ds_condition.set("reqPossessCd", lc_reqPossessCd.getValue());
    ds_condition.set("reqLuggageInsuranceEndDt", ed_reqLuggageInsuranceEndDt.getValue())
};


// for=ds_vehclInsuranceChangeMgnt event=OnLoadCompleted(rowCnt)
scwin.sbm_search_submitdone = function (e) {
    let rowCnt = ds_vehclInsuranceChangeMgnt.getTotalRow();
    if (rowCnt == 0) {
        totalRows.setValue(rowCnt);
        $c.win.alert("조회결과가 존재하지 않습니다.");
        return;
    }
    else {
        totalRows.setValue(rowCnt)
        $c.gus.cfEnableObjects([btn_Save]);
    }
};

// <!-- 작업구분 Combo 선택 -->
// for=gr_vehclInsuranceChangeMgnt event=OnCloseUp(row,colid)
scwin.gr_vehclInsuranceChangeMgnt_oneditend = function (rowIndex, columnIndex, value) {

    let rowData = ds_vehclInsuranceChangeMgnt.getRowJSON(rowIndex);

    if (columnIndex == "selfVehclYn") {
        if (rowData["selfVehclYn"] == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "selfVehclStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "selfVehclEndDt", '');
        }
    }

    if (columnIndex == "sfdmgVehclYn") {
        if (rowData["sfdmgVehclYn"] == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "sfdmgVehclStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "sfdmgVehclEndDt", '');
        }
    }

    if (columnIndex == "glassYn") {
        if (rowData["glassYn"] == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "glassStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "glassEndDt", '');
        }
    }

    if (columnIndex == "frizYn") {
        if (rowData["frizYn"] == 0) {
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "frizStdDt", '');
            ds_vehclInsuranceChangeMgnt.setCellData(rowIndex, "frizEndDt", '');
        }
    }
};

// <!-- 클릭 이벤트 처리  -->
// for=gr_vehclInsuranceChangeMgnt event=OnClick(Row,Colid)
scwin.gr_vehclInsuranceChangeMgnt_oncellclick = function (rowIndex, columnIndex, columnId) {

    let rowData = ds_vehclInsuranceChangeMgnt.getRowJSON(rowIndex);

    if (columnId == "selfVehclStdDt" || columnId == "selfVehclEndDt") {
        if (rowData["selfVehclYn"] == 0) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'selfVehclStdDt', true);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'selfVehclEndDt', true);
        }
        if (rowData["selfVehclYn"] == 1) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'selfVehclStdDt', false);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'selfVehclEndDt', false);
        }
    }

    if (columnId == "sfdmgVehclStdDt" || columnId == "sfdmgVehclEndDt") {
        if (rowData["sfdmgVehclYn"] == 0) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'sfdmgVehclStdDt', true);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'sfdmgVehclEndDt', true);
        }
        if (rowData["sfdmgVehclYn"] == 1) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'sfdmgVehclStdDt', false);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'sfdmgVehclEndDt', false);
        }
    }

    if (columnId == "glassStdDt" || columnId == "glassEndDt") {
        if (rowData["glassYn"] == 0) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'glassStdDt', true);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'glassEndDt', true);
        }
        if (rowData["glassYn"] == 1) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'glassStdDt', false);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'glassEndDt', false);
        }
    }

    if (columnId == "frizStdDt" || columnId == "frizEndDt") {
        if (rowData["frizYn"] == 0) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'frizStdDt', true);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'frizEndDt', true);
        }
        if (rowData["frizYn"] == 1) {
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'frizStdDt', false);
            gr_vehclInsuranceChangeMgnt.setCellReadOnly(rowIndex, 'frizEndDt', false);
        }
    }
};

scwin.gr_vehclInsuranceChangeMgnt_onheaderclick = function (headerId) {
    if (headerId == "chk_header") {
        if (gr_vehclInsuranceChangeMgnt.getHeaderValue("chk_header") == "T") {
            for (var i = 0; i < ds_vehclInsuranceChangeMgnt.getTotalRow(); i++) {
                gr_vehclInsuranceChangeMgnt.setCellData(i, "chkBox", "T"); //체크
            }
        } else {
            for (var i = 0; i < ds_vehclInsuranceChangeMgnt.getTotalRow(); i++) {
                gr_vehclInsuranceChangeMgnt.setCellData(i, "chkBox", "F"); //체크해제
            }
        }
    }
};



// <!-- 그리드 정보를 변경하려고 할 경우 -->
// for=ds_vehclInsuranceChangeMgnt event=onColumnChanged(row,colid)
scwin.ds_vehclInsuranceChangeMgnt_oncelldatachange = function (info) {

    // to-do 
    let row = info.newRowIndex;
    let colid = info.columnId;

    let chkBoxVal = ds_vehclInsuranceChangeMgnt.getCellData(row, "chkBox");
    if (chkBoxVal != "T") {
        return;
    }

    let rowCnt = ds_vehclInsuranceChangeMgnt.getTotalRow();
    // 자동차보험 보험기간 변경

    if (colid == "carInsuranceYearStdDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "carInsuranceYearStdDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "carInsuranceYearStdDt", val);
            }
        }
    }
    if (colid == "carInsuranceYearEndDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "carInsuranceYearEndDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "carInsuranceYearEndDt", val);
            }
        }
    }

    // 자동차보험 기본정보 변경
    if (colid == "objectLimitCd") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "objectLimitCd");
                ds_vehclInsuranceChangeMgnt.setCellData(i, "objectLimitCd", val);
            }
        }
    }
    if (colid == "driverAge") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "driverAge")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "driverAge", val);
            }
        }
    }

    // 자동차보험 자차정보 변경
    if (colid == "selfVehclYn") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "selfVehclYn")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "selfVehclYn", val);
            }

            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "selfVehclYn") == 0) {
                ds_vehclInsuranceChangeMgnt.setCellData(i, "selfVehclStdDt", '');
                ds_vehclInsuranceChangeMgnt.setCellData(i, "selfVehclEndDt", '');
            }
        }
    }
    if (colid == "selfVehclStdDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "selfVehclYn") == 1) {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "selfVehclStdDt");
                ds_vehclInsuranceChangeMgnt.setCellData(i, "selfVehclStdDt", val);
            }
        }
    }
    if (colid == "selfVehclEndDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "selfVehclYn") == 1) {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "selfVehclEndDt");
                ds_vehclInsuranceChangeMgnt.setCellData(i, "selfVehclEndDt", val);
            }
        }
    }

    // 자동차보험 자손정보 변경
    if (colid == "sfdmgVehclYn") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "sfdmgVehclYn")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "sfdmgVehclYn", val);
            }

            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "sfdmgVehclYn") == 0) {
                ds_vehclInsuranceChangeMgnt.setCellData(i, "sfdmgVehclStdDt", '');
                ds_vehclInsuranceChangeMgnt.setCellData(i, "sfdmgVehclEndDt", '');
            }
        }
    }
    if (colid == "sfdmgVehclStdDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "sfdmgVehclYn") == 1) {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "sfdmgVehclStdDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "sfdmgVehclStdDt", val);
            }
        }
    }
    if (colid == "sfdmgVehclEndDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "sfdmgVehclYn") == 1) {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "sfdmgVehclEndDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "sfdmgVehclEndDt", val);
            }
        }
    }

    // 적재물보험 보험기간 변경
    if (colid == "luggageInsuranceYearStdDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "luggageInsuranceYearStdDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "luggageInsuranceYearStdDt", val);
            }
        }
    }
    if (colid == "luggageInsuranceYearEndDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "luggageInsuranceYearEndDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "luggageInsuranceYearEndDt", val);
            }
        }
    }

    // 적재물보험 기본정보 변경
    if (colid == "guaranteeLimitCd") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "guaranteeLimitCd");
                ds_vehclInsuranceChangeMgnt.setCellData(i, "guaranteeLimitCd", val);
            }
        }
    }

    // 적재물보험 유리정보 변경
    if (colid == "glassYn") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "glassYn")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "glassYn", val);
            }

            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "glassYn") == 0) {
                ds_vehclInsuranceChangeMgnt.setCellData(i, "glassStdDt", '');
                ds_vehclInsuranceChangeMgnt.setCellData(i, "glassEndDt", '');

            }
        }
    }
    if (colid == "glassStdDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "glassYn") == 1) {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "glassStdDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "glassStdDt", val);
            }
        }
    }
    if (colid == "glassEndDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "glassYn") == 1) {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "glassEndDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "glassEndDt", val);
            }
        }
    }

    // 적재물보험 냉동정보 변경
    if (colid == "frizYn") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T") {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "frizYn");
                ds_vehclInsuranceChangeMgnt.setCellData(i, "frizYn", val);
            }
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "frizYn") == 0) {
                ds_vehclInsuranceChangeMgnt.setCellData(i, "frizStdDt", '');
                ds_vehclInsuranceChangeMgnt.setCellData(i, "frizEndDt", '');

            }
        }
    }
    if (colid == "frizStdDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "frizYn") == 1) {
