                ds_vehclInsuranceChangeMgnt.setCellData(i, "frizStdDt", val);
            }
        }
    }
    if (colid == "frizEndDt") {
        for (var i = 0; i < rowCnt; i++) {
            if (ds_vehclInsuranceChangeMgnt.getCellData(i, "chkBox") == "T"
                && ds_vehclInsuranceChangeMgnt.getCellData(i, "frizYn") == 1) {
                let val = ds_vehclInsuranceChangeMgnt.getCellData(row, "frizEndDt")
                ds_vehclInsuranceChangeMgnt.setCellData(i, "frizEndDt", val);
            }
        }
    }
